import{_ as o,o as t,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"72. Professional Development Leave","description":"","frontmatter":{"title":"72. Professional Development Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/72-professional-development-leave.md","filePath":"ebas/biomedical-engineers/education-pd/72-professional-development-leave.md"}'),i={name:"ebas/biomedical-engineers/education-pd/72-professional-development-leave.md"};function s(a,e,p,l,d,m){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_72-professional-development-leave" tabindex="-1">72. Professional Development Leave <a class="header-anchor" href="#_72-professional-development-leave" aria-label="Permalink to &quot;72. Professional Development Leave&quot;">​</a></h1><p><strong>72.1</strong> Professional Development is the means by which members of a profession maintain, improve and broaden their knowledge and expertise, and develop personal and professional qualities by:</p><p><strong>(a)</strong> reviewing practice;</p><p><strong>(b)</strong> identifying learning needs;</p><p><strong>(c)</strong> planning and participating in relevant learning activities; and</p><p><strong>(d)</strong> reflecting on the value of those activities. Professional development may be for the Employee’s current position or job, or another position or job that would be covered by this Agreement.</p><p><strong>72.2</strong> Professional Development Activities Professional development activities include, but are not limited to:</p><p><strong>(a)</strong> short courses;</p><p><strong>(b)</strong> further tertiary studies;</p><p><strong>(c)</strong> research;</p><p><strong>(d)</strong> study (including home study);</p><p><strong>(e)</strong> training;</p><p><strong>(f)</strong> attending a conference;</p><p><strong>(g)</strong> attending a seminar;</p><p><strong>(h)</strong> attending a webinar; and</p><p><strong>(i)</strong> attending a lecture.</p><p><strong>72.3</strong> Amount of Professional Development Leave</p><p><strong>(a)</strong> A full-time Employee (including a fixed-term Employee) is entitled to seven (7) days’ paid professional development leave per calendar year, in addition to other prescribed leave entitlements. Part-time Employees have a pro rata entitlement.</p><p><strong>(b)</strong> An Employee may utilise professional development leave for part of a single day.</p><p><strong>72.4</strong> Payment Day for the purposes of professional development leave is the Employee&#39;s usual shift length on the day the leave is taken.</p><p><strong>72.5</strong> Accumulation of Professional Development Leave The leave is cumulative over two (2) calendar years.</p><p><strong>72.6</strong> Application Process</p><p><strong>(a)</strong> Professional Development Leave is available only on written application by the Employee.</p><p><strong>(b)</strong> Where practicable, the application must be made at least six (6) weeks prior to the proposed professional development leave date(s). Nothing prevents an application being made less than six (6) weeks before the proposed professional development leave activity.</p><p><strong>(c)</strong> The application must include:</p><p><strong>(i)</strong> the proposed date(s);</p><p><strong>(ii)</strong> a brief description of the nature of the professional development activity to be undertaken and its applicability to the Employee’s profession; and</p><p><strong>(iii)</strong> where the leave is taken to attend a conference or seminar, the name, venue and date/time.</p><p><strong>(d)</strong> Applications for leave may include the period of time in which the Employee is traveling to and from the Professional Development activity.</p><p><strong>72.7</strong> Response to Application</p><p><strong>(a)</strong> Approval of the application will not be unreasonably withheld by the Employer.</p><p><strong>(b)</strong> The Employer must respond to the Employee’s application in writing as soon as possible, but no later than seven (7) days of the application being made.</p><p><strong>(c)</strong> If leave is not approved the reasons will be included in the written notification to the Employee.</p><p><strong>72.8</strong> Professional development activities occurring on a day the Employee would not otherwise work</p><p><strong>(a)</strong> Where a request for professional development leave which is approved by the Employer covers a period where the Employee is not rostered to work (e.g. on weekends, ADOs or after hours), the Employer will provide time off in lieu for such period of the professional development activity.</p><p><strong>(b)</strong> Time off must be taken at a time or times agreed by the Employee and Employer.</p><p><strong>(c)</strong> Time in lieu in this subclause 72.8 is on the basis of time for time at ordinary rates and does not include any benefit or payment for any overtime, penalties or allowances under this Agreement which would normally be paid for such periods of duty.</p><p><strong>72.9</strong> Report Back An Employee may be required to provide a reasonable report back on a seminar or conference, provided they are:</p><p><strong>(a)</strong> advised of this requirement prior to the Employee attending the professional development activity, and</p><p><strong>(b)</strong> allocated sufficient time during their ordinary hours of work to prepare for and deliver this.</p><p><strong>72.10</strong> Mandatory Training Any education or training (however titled):</p><p><strong>(a)</strong> the Employer requires an Employee to attend, such as fire, workplace bullying and equal opportunity training; and/or</p><p><strong>(b)</strong> that is necessary for an Employee to perform their position/role, such as learning how to use a new piece of equipment or updates on policies / procedure; will occur within an Employee&#39;s paid time and no deduction will be made to an Employee&#39;s professional development leave entitlement for such education or training.</p><p><strong>72.11</strong> Childcare Expenses</p><p><strong>(a)</strong> Upon the provision of evidence, an Employee will be entitled to the reimbursement of reasonable additional childcare expenses incurred during their approved Professional Development Leave where the Employee is the primary care giver of a child or children and has responsibility for the child(ren) during the professional development activity.</p><p><strong>(b)</strong> Receipts identifying the expense incurred must be provided to the Employer as soon as practicable after the Professional Development Leave.</p><p><strong>(c)</strong> Employees will be entitled to a maximum reimbursement of $250 per period of Professional Development Leave.</p>',47)])])}const h=o(i,[["render",s]]);export{c as __pageData,h as default};
